#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[300005]; scanf("%s", s);
        int pos = -1;
        for (int i = 0; i < N-1; ++i) {
            if (s[i] > s[i+1]) { pos = i; break; }
        }
        if (pos == -1) pos = N-1;
        for (int i = 0; i < N; ++i) {
            if (i != pos) putchar(s[i]);
        }
        putchar('\n');
    }
    return 0;
}

